    def dfs(node):
        if node is None:
            return 0
        left = dfs(node.left)
        right = dfs(node.right)
        return max(left, right) + 1

    def rotate(node):
        if node is None:
            return 0
        left = rotate(node.left)
        right = rotate(node.right)
        node.left, node.right = node.right, node.left
        return max(left, right) + 1

